import 'dart:convert'; import 'package:flutter/material.dart'; import '../models/product.dart'; import '../services/api_service.dart'; import '../services/ws_service.dart'; import '../services/isar_service.dart'; import '../config.dart'; class WaiterScreen extends StatefulWidget { const WaiterScreen({super.key}); @override State<WaiterScreen> createState() => _WaiterScreenState(); } class _WaiterScreenState extends State<WaiterScreen> { List<Product> products = []; final List<Map<String, dynamic>> cart = []; String selectedCategory = "BEBIDAS"; bool isLoading = true, _takeout = false; final TextEditingController _tableCtrl = TextEditingController(); @override void initState() { super.initState(); _loadMenu(); WsService.connect("waiter", (msg) { if (msg["type"] == "price_updated" || msg["type"] == "price_refresh") _loadMenu(); }); } Future<void> _loadMenu() async { setState(() => isLoading = true); try { products = await ApiService.getProducts(); } catch (_) {} finally { setState(() => isLoading = false); } } void _addToCart(Product p) => setState(() => cart.add({"product_id": p.id, "quantity": 1, "notes": []})); Future<void> _sendOrder() async { if (cart.isEmpty) return; final payload = {"table": _takeout ? null : (int.tryParse(_tableCtrl.text) ?? 1), "takeout": _takeout, "items": cart}; try { await ApiService.createOrder(payload); ScaffoldMessenger.of(context).showSnackBar(const SnackBar(content: Text("✅ Pedido enviado"))); } catch (_) { await IsarService.enqueue(jsonEncode(payload)); ScaffoldMessenger.of(context).showSnackBar(const SnackBar(content: Text("📦 Guardado offline"))); } finally { setState(() => cart.clear()); } } @override Widget build(BuildContext context) { final cats = ["BEBIDAS", "APERITIVOS", "HAMBURGUESAS", "PLATOS FUERTES", "COMBOS"]; final filtered = products.where((p) => p.category == selectedCategory && p.available).toList(); return Scaffold(appBar: AppBar(title: const Text("👨‍🍳 Mesero")), body: Column(children: [ Padding(padding: const EdgeInsets.all(8), child: Row(children: [ Expanded(child: TextField(controller: _tableCtrl, keyboardType: TextInputType.number, decoration: const InputDecoration(labelText: "Mesa", border: OutlineInputBorder()))), const SizedBox(width: 8), Switch(value: _takeout, onChanged: (v) => setState(() => _takeout = v)), const Text("Para llevar") ])), SingleChildScrollView(scrollDirection: Axis.horizontal, child: Row(children: cats.map((c) => ChoiceChip(label: Text(c), selected: c == selectedCategory, onSelected: (_) => setState(() => selectedCategory = c))).toList())), Expanded(child: isLoading ? const Center(child: CircularProgressIndicator()) : GridView.builder(padding: const EdgeInsets.all(8), gridDelegate: const SliverGridDelegateWithFixedCrossAxisCount(crossAxisCount: 2, childAspectRatio: 1.5, crossAxisSpacing: 8, mainAxisSpacing: 8), itemCount: filtered.length, itemBuilder: (_, i) => Card(child: InkWell(onTap: () => _addToCart(filtered[i]), child: Padding(padding: const EdgeInsets.all(8), child: Column(mainAxisAlignment: MainAxisAlignment.center, children: [ Text(filtered[i].name, textAlign: TextAlign.center, style: const TextStyle(fontWeight: FontWeight.bold)), Text("\$${filtered[i].price.toStringAsFixed(2)}", style: const TextStyle(color: Colors.green, fontSize: 16)) ])))))), if (cart.isNotEmpty) Container(padding: const EdgeInsets.all(8), color: Colors.grey[200], child: Column(children: [ Text("🛒 \${cart.length} ítems"), ElevatedButton(onPressed: _sendOrder, child: const Text("ENVIAR PEDIDO")) ])) ])); } }
